class Solution:
    def maximumScore(self, scores, edges):
        from collections import defaultdict
        adj = defaultdict(set)
        for a, b in edges:
            adj[a].add(b)
            adj[b].add(a)
        best = -1
        for b, c in edges:
            for a in adj[b]:
                if a == c:
                    continue
                for d in adj[c]:
                    if d == a or d == b:
                        continue
                    total = scores[a] + scores[b] + scores[c] + scores[d]
                    if total > best:
                        best = total
        return best

