class Solution:
    def maximumScore(self, scores, edges):
        import heapq
        from collections import defaultdict
        nb = defaultdict(list)
        for a, b in edges:
            nb[a].append((scores[b], b))
            nb[b].append((scores[a], a))
        top = {}
        for node, lst in nb.items():
            top[node] = heapq.nlargest(3, lst)
        best = -1
        for u, v in edges:
            for su, a in top.get(u, []):
                if a == v:
                    continue
                for sv, d in top.get(v, []):
                    if d == u or d == a:
                        continue
                    total = scores[u] + scores[v] + su + sv
                    if total > best:
                        best = total
        return best

