var maximumScore = function(scores, edges) {
    const nb = new Map();
    const push = (x, y) => {
        if (!nb.has(x)) nb.set(x, []);
        nb.get(x).push([scores[y], y]);
    };
    for (const [a, b] of edges) { push(a, b); push(b, a); }
    const top = new Map();
    for (const [node, lst] of nb) {
        lst.sort((p, q) => q[0] - p[0]);
        top.set(node, lst.slice(0, 3));
    }
    let best = -1;
    for (const [u, v] of edges) {
        const tu = top.get(u) || [];
        const tv = top.get(v) || [];
        for (const [su, a] of tu) {
            if (a === v) continue;
            for (const [sv, d] of tv) {
                if (d === u || d === a) continue;
                const total = scores[u] + scores[v] + su + sv;
                if (total > best) best = total;
            }
        }
    }
    return best;
};
